export interface DBEntry {
  id: string;
  [key: string]: any;
}

export interface Collection {
  name: string;
  entries: DBEntry[];
}

export interface Project {
  id: string;
  name: string;
  apiKey: string;
  collections: Collection[];
  createdAt: string;
}

export type LogType = 'info' | 'success' | 'error' | 'warning';

export interface LogEntry {
  timestamp: string;
  type: LogType;
  message: string;
}

export enum ViewState {
  LANDING = 'LANDING',
  DASHBOARD = 'DASHBOARD',
  DOCS = 'DOCS',
  PLAYGROUND = 'PLAYGROUND'
}

import { Project, DBEntry } from '../types';

// This service simulates the behavior of the future backend and the client-side SDK.
// It uses localStorage to persist data for the demo session.

const STORAGE_KEY = 'perdb_demo_data';

const getProjects = (): Project[] => {
  const data = localStorage.getItem(STORAGE_KEY);
  return data ? JSON.parse(data) : [];
};

const saveProjects = (projects: Project[]) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(projects));
};

export const MockSDK = {
  // --- Management API (Simulating Dashboard Actions) ---

  createProject: async (name: string): Promise<Project> => {
    await new Promise(r => setTimeout(r, 600)); // Simulate net lag
    const projects = getProjects();
    const newProject: Project = {
      id: `proj_${Math.random().toString(36).substr(2, 9)}`,
      name,
      apiKey: `pk_live_${Math.random().toString(36).substr(2, 16)}`,
      collections: [],
      createdAt: new Date().toISOString()
    };
    projects.push(newProject);
    saveProjects(projects);
    return newProject;
  },

  getAllProjects: async (): Promise<Project[]> => {
    return getProjects();
  },

  getProject: async (id: string): Promise<Project | undefined> => {
    return getProjects().find(p => p.id === id);
  },

  // --- Runtime API (Simulating what Perchance users call) ---

  // PerDB.collection('users').add({ name: '...' })
  runtimeAdd: async (apiKey: string, collectionName: string, data: any): Promise<any> => {
    await new Promise(r => setTimeout(r, 300));
    const projects = getProjects();
    const projectIndex = projects.findIndex(p => p.apiKey === apiKey);

    if (projectIndex === -1) throw new Error("Invalid API Key");

    const project = projects[projectIndex];
    let collection = project.collections.find(c => c.name === collectionName);

    if (!collection) {
      // Auto-create collection if it doesn't exist (Firestore style)
      collection = { name: collectionName, entries: [] };
      project.collections.push(collection);
    }

    const newEntry: DBEntry = {
      id: `doc_${Math.random().toString(36).substr(2, 9)}`,
      ...data,
      _created: new Date().toISOString()
    };

    collection.entries.push(newEntry);
    projects[projectIndex] = project;
    saveProjects(projects);
    return newEntry;
  },

  // PerDB.collection('users').get()
  runtimeGet: async (apiKey: string, collectionName: string): Promise<DBEntry[]> => {
    await new Promise(r => setTimeout(r, 300));
    const projects = getProjects();
    const project = projects.find(p => p.apiKey === apiKey);
    if (!project) throw new Error("Invalid API Key");

    const collection = project.collections.find(c => c.name === collectionName);
    return collection ? collection.entries : [];
  }
};

import { GoogleGenAI } from "@google/genai";

export const generateCodeSnippet = async (prompt: string): Promise<string> => {
  if (!process.env.API_KEY) {
    return "// API Key not configured. Using fallback example.\n// PerDB.collection('items').add({ name: 'Sword', power: 10 });";
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const systemInstruction = `
      You are an expert developer for PerDB, a database platform for Perchance.org generators.
      PerDB allows users to store data in the cloud.

      The SDK Syntax is:
      1. Initialization: const db = new PerDB("API_KEY");
      2. Add Data: await db.collection("collection_name").add({ key: "value" });
      3. Get Data: await db.collection("collection_name").get(); (Returns array)

      Generate a VALID JavaScript code snippet for a Perchance HTML module based on the user's request.
      Do not include markdown backticks. Just the raw code. Keep it concise.
      Add comments explaining what it does.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        thinkingConfig: { thinkingBudget: 0 } 
      }
    });

    return response.text || "// Could not generate code.";
  } catch (error) {
    console.error("AI Generation Error:", error);
    return "// Error generating code. Please try again.";
  }
};

import React from 'react';
import { LucideIcon } from 'lucide-react';

// --- Button ---
interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'danger';
  icon?: LucideIcon;
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, variant = 'primary', className = '', icon: Icon, isLoading, disabled, ...props 
}) => {
  const baseStyle = "inline-flex items-center justify-center px-4 py-2 rounded-lg font-medium transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-slate-900 disabled:opacity-50 disabled:cursor-not-allowed text-sm";

  const variants = {
    primary: "bg-brand-600 hover:bg-brand-500 text-white shadow-lg shadow-brand-900/50 focus:ring-brand-500",
    secondary: "bg-slate-700 hover:bg-slate-600 text-slate-100 focus:ring-slate-500",
    outline: "border border-slate-600 hover:border-brand-500 hover:text-brand-400 text-slate-400 bg-transparent focus:ring-brand-500",
    danger: "bg-red-600 hover:bg-red-500 text-white focus:ring-red-500",
  };

  return (
    <button 
      className={`${baseStyle} ${variants[variant]} ${className}`} 
      disabled={isLoading || disabled}
      {...props}
    >
      {isLoading ? (
        <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
      ) : Icon ? (
        <Icon className="w-4 h-4 mr-2" />
      ) : null}
      {children}
    </button>
  );
};

// --- Card ---
export const Card: React.FC<{ children: React.ReactNode; className?: string; title?: string }> = ({ children, className = '', title }) => (
  <div className={`bg-slate-800/50 border border-slate-700/50 backdrop-blur-sm rounded-xl p-6 ${className}`}>
    {title && <h3 className="text-lg font-semibold text-slate-100 mb-4">{title}</h3>}
    {children}
  </div>
);

// --- Input ---
interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  label?: string;
}

export const Input: React.FC<InputProps> = ({ label, className = '', ...props }) => (
  <div className="w-full">
    {label && <label className="block text-xs font-medium text-slate-400 mb-1.5 uppercase tracking-wider">{label}</label>}
    <input 
      className={`w-full bg-slate-900/50 border border-slate-700 rounded-lg px-4 py-2.5 text-slate-200 placeholder-slate-500 focus:border-brand-500 focus:ring-1 focus:ring-brand-500 focus:outline-none transition-colors ${className}`}
      {...props}
    />
  </div>
);

// --- Badge ---
export const Badge: React.FC<{ children: React.ReactNode; variant?: 'success' | 'warning' | 'info' }> = ({ children, variant = 'info' }) => {
  const styles = {
    success: 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20',
    warning: 'bg-amber-500/10 text-amber-400 border-amber-500/20',
    info: 'bg-brand-500/10 text-brand-400 border-brand-500/20',
  };
  return (
    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium border ${styles[variant]}`}>
      {children}
    </span>
  );
};

