      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Project List */}
          <div className="lg:col-span-1 space-y-4">
            {projects.map(project => (
              <div 
                key={project.id}
                onClick={() => setSelectedProject(project)}
                className={`p-4 rounded-lg border cursor-pointer transition-all ${selectedProject?.id === project.id ? 'bg-brand-900/20 border-brand-500/50' : 'bg-slate-800 border-slate-700 hover:border-slate-600'}`}
              >
                <div className="flex justify-between items-start">
                  <h3 className="font-semibold text-slate-100">{project.name}</h3>
                  <Badge>{project.collections.length} Collections</Badge>
                </div>
                <div className="mt-3 text-xs text-slate-500 font-mono">ID: {project.id}</div>
              </div>
            ))}
          </div>

          {/* Project Details */}
          <div className="lg:col-span-2">
            {selectedProject ? (
              <div className="space-y-6">
                <Card title="Configuration">
                  <div className="grid gap-6">
                    <div>
                      <label className="text-xs font-medium text-slate-400 uppercase tracking-wider">Public API Key</label>
                      <div className="flex mt-1.5">
                        <code className="flex-1 bg-slate-950 rounded-l-lg border border-r-0 border-slate-700 px-3 py-2 text-sm text-brand-300 font-mono overflow-x-auto whitespace-nowrap">
