          <div className="md:hidden border-b border-slate-800 bg-slate-950 px-4 pt-2 pb-4 space-y-2 shadow-xl animate-in slide-in-from-top-2">
            <button
              onClick={() => handleNavClick(ViewState.LANDING)}
              className={`flex items-center w-full px-3 py-3 rounded-lg text-sm font-medium transition-colors ${
                view === ViewState.LANDING ? 'bg-brand-900/50 text-brand-400' : 'text-slate-400 hover:bg-slate-800 hover:text-white'
              }`}
            >
              <HomeIcon className="w-4 h-4 mr-3" /> Home
            </button>
            <button
              onClick={() => handleNavClick(ViewState.DASHBOARD)}
              className={`flex items-center w-full px-3 py-3 rounded-lg text-sm font-medium transition-colors ${
                view === ViewState.DASHBOARD ? 'bg-brand-900/50 text-brand-400' : 'text-slate-400 hover:bg-slate-800 hover:text-white'
              }`}
            >
              <LayoutDashboard className="w-4 h-4 mr-3" /> Dashboard
            </button>
            <button
              onClick={() => handleNavClick(ViewState.DOCS)}
              className={`flex items-center w-full px-3 py-3 rounded-lg text-sm font-medium transition-colors ${
                view === ViewState.DOCS ? 'bg-brand-900/50 text-brand-400' : 'text-slate-400 hover:bg-slate-800 hover:text-white'
              }`}
            >
              <Book className="w-4 h-4 mr-3" /> Docs
            </button>
            <button
              onClick={() => handleNavClick(ViewState.PLAYGROUND)}
              className={`flex items-center w-full px-3 py-3 rounded-lg text-sm font-medium transition-colors ${
                view === ViewState.PLAYGROUND ? 'bg-brand-900/50 text-brand-400' : 'text-slate-400 hover:bg-slate-800 hover:text-white'
              }`}
            >
              <Code className="w-4 h-4 mr-3" /> Playground
            </button>
          </div>
        )}
      </nav>

      {/* Main Content */}
      <main>
        {renderPage()}
      </main>

      {/* Footer */}
      {view === ViewState.LANDING && (
        <footer className="border-t border-slate-900 bg-slate-950 py-12">
          <div className="max-w-7xl mx-auto px-4 text-center">
            <p className="text-slate-500 text-sm">
              © {new Date().getFullYear()} PerDB. Built for the Perchance Community.
            </p>
          </div>
        </footer>
      )}
    </div>
  );
};

export default App;
